 24→
 25→//// Pooling Functions
 26→
 27→void riscv_nn_avepool_HWC_s8(q7_t * in_tensor,
 28→                             const uint16_t in_tensor_batch,
 29→                             const uint16_t in_tensor_dim,
 30→                             const uint16_t in_tensor_ch,
 31→                             const uint16_t ker_dim,
 32→                             const uint16_t pad,
 33→                             const uint16_t stride,
 34→                             const uint16_t out_tensor_dim,
 35→                             q7_t * in_tmp_buf,
 36→                             q7_t * out_tensor)
 37→{
 38→#ifdef ENA_EMPTY_FUN
 39→    //empty body
 40→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC) && 0
 41→    // the v-ext algorithm is modifed, please remember to update the intrinsic version v-ext algorithm
 42→
 43→    long out_x, out_y, k_x, k_y, in_x, in_y;
 44→
 45→    for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
 46→    {
 47→        long ker_y_start = MAX(0, in_y);
 48→        long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
 49→        for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
 50→        {
 51→            long count = 0;
 52→            long ker_x_start = MAX(0, in_x);
 53→            long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
 54→            long cur_ch = 0, vl = 0;
 55→
 56→            //calculate the numbers of kernel nodes in the range of input tensor
 57→            for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 58→            {
 59→                for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 60→                {
 61→                    count++;
 62→                }
 63→            }
 64→
 65→            long in_tensor_ch2 = in_tensor_ch;
 66→            while(in_tensor_ch2 > 0)
 67→            {
 68→                // reset the accumulators
 69→                vl = __riscv_vsetvl_e16m8(in_tensor_ch2);
 70→                vint16m8_t vAcc_i16 = __riscv_vundefined_i16m8();
 71→                vAcc_i16 = __riscv_vand(vAcc_i16, 0, vl);
 72→                vl = __riscv_vsetvl_e8m4(in_tensor_ch2);
 73→
 74→                for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 75→                {
 76→                    for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 77→                    {
 78→                        q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
 79→                        vint8m4_t vIn_ptr_i8 = __riscv_vle8_v_i8m4(in_ptr, vl);
 80→                        vAcc_i16 = __riscv_vwadd_wv(vAcc_i16, vIn_ptr_i8, vl);
 81→                    }
 82→                }
 83→
 84→                vl = __riscv_vsetvl_e16m8(in_tensor_ch2);
 85→                vAcc_i16 = __riscv_vdiv(vAcc_i16, count, vl);
 86→                vl = __riscv_vsetvl_e8m4(in_tensor_ch2);
 87→                vint8m4_t vResult_i8 = __riscv_vnsra(vAcc_i16, 0, vl);
 88→                __riscv_vse8(out_tensor, vResult_i8, vl);
 89→                out_tensor += vl;
 90→                cur_ch += vl;
 91→                in_tensor_ch2 -= vl;
 92→            }
 93→        }
 94→    }
 95→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
 96→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
 97→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
 98→
 99→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
100→    {
101→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
102→        {
103→            long ker_y_start = MAX(0, in_y);
104→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
105→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
106→            {
107→                long ker_x_start = MAX(0, in_x);
108→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
109→                long cur_ch = 0, vl = 0;
110→
111→                if ((ker_y_end > ker_y_start) &&
112→                    (ker_x_end > ker_x_start))
113→                {
114→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
115→                    long in_tensor_ch2 = in_tensor_ch;
116→                    // Precompute row stride for pointer advancement
117→                    long row_stride = in_tensor_dim * in_tensor_ch;
118→
119→                    while(in_tensor_ch2 > 0)
120→                    {
121→                        // Use e8/M4 -> s16 widening (VL=512 at VLEN=1024)
122→                        // instead of e8/M2 -> s32 quad-widening (VL=256)
123→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
124→                        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
125→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
126→
127→                        q7_t *row_ptr = in_tensor + (ker_y_start * row_stride) + (ker_x_start * in_tensor_ch) + cur_ch;
128→                        for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
129→                        {
130→                            q7_t *col_ptr = row_ptr;
131→                            for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
132→                            {
133→                                NDS_VEC_VLE8_V(NDS_VEC_V8, col_ptr);
134→                                NDS_VEC_VWADD_WV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
135→                                col_ptr += in_tensor_ch;
136→                            }
137→                            row_ptr += row_stride;
138→                        }
139→
140→                        // Divide at e16/M8, then narrow once to e8
141→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
142→                        NDS_VEC_VDIV_VX(NDS_VEC_V0, NDS_VEC_V0, count);
143→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
144→                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
145→                        NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
146→                        out_tensor += vl;
147→                        cur_ch += vl;
148→                        in_tensor_ch2 -= vl;
149→                    }
150→                }
151→                else
152→                {
153→                    // for those outputs in boundary as there is no overlapping
154→                    // between ifm and kernel
155→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
156→                    out_tensor += in_tensor_ch;
157→                }
158→            }
159→        }
160→        in_tensor += input_len;
161→    }
162→#elif defined(ENA_DSP_ISA_64)
163→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
164→    const long_t cst_one_q15x4 = 0x0001000100010001;
165→
166→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
167→    {
168→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
169→        {
170→            long ker_y_start = MAX(0, in_y);
171→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
172→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
173→            {
174→                long ker_x_start = MAX(0, in_x);
175→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
176→                uint32_t cur_ch;
177→
178→                if ((ker_y_end > ker_y_start) &&
179→                    (ker_x_end > ker_x_start))
180→                {
181→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
182→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
183→                    {
184→                        suni_t sum_q31x2_0;
185→                        suni_t sum_q31x2_1;
186→                        suni_t sum_q31x2_2;
187→                        suni_t sum_q31x2_3;
188→                        sum_q31x2_0.l0 = 0;
189→                        sum_q31x2_1.l0 = 0;
190→                        sum_q31x2_2.l0 = 0;
191→                        sum_q31x2_3.l0 = 0;
192→
193→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
194→                        {
195→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
196→                            {
197→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
198→                                suni_t in_q7x8 = simd_load_8(pIn, 0);
199→                                long in_q15x4_0 = NDS_DSP_SUNPKD810(in_q7x8.l0);
200→                                long in_q15x4_1 = NDS_DSP_SUNPKD832(in_q7x8.l0);
201→                                sum_q31x2_0.l0 = NDS_DSP_KMABB(sum_q31x2_0.l0, in_q15x4_0, cst_one_q15x4);
202→                                sum_q31x2_1.l0 = NDS_DSP_KMATT(sum_q31x2_1.l0, in_q15x4_0, cst_one_q15x4);
203→                                sum_q31x2_2.l0 = NDS_DSP_KMABB(sum_q31x2_2.l0, in_q15x4_1, cst_one_q15x4);
204→                                sum_q31x2_3.l0 = NDS_DSP_KMATT(sum_q31x2_3.l0, in_q15x4_1, cst_one_q15x4);
205→                            }
206→                        }
207→
208→                        suni_t out_q7x8;
209→                        out_q7x8.b8.b0 = sum_q31x2_0.b32.w0 / count;
210→                        out_q7x8.b8.b1 = sum_q31x2_1.b32.w0 / count;
211→                        out_q7x8.b8.b2 = sum_q31x2_2.b32.w0 / count;
212→                        out_q7x8.b8.b3 = sum_q31x2_3.b32.w0 / count;
213→                        out_q7x8.b8.b4 = sum_q31x2_0.b32.w1 / count;
214→                        out_q7x8.b8.b5 = sum_q31x2_1.b32.w1 / count;
215→                        out_q7x8.b8.b6 = sum_q31x2_2.b32.w1 / count;
216→                        out_q7x8.b8.b7 = sum_q31x2_3.b32.w1 / count;
217→                        simd_save_8((s8_t*)out_tensor, out_q7x8.l0);
218→                        out_tensor += SIMD_NUM_Q7;
219→                    }
220→
221→                    // rest channels
222→                    for (; cur_ch < in_tensor_ch; cur_ch++)
223→                    {
224→                        int sum = 0;
225→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
226→                        {
227→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
228→                            {
229→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
230→                                sum += *pIn;
231→                            }
232→                        }
233→
234→                        *out_tensor++ = sum / count;
235→                    }
236→                }
237→                else
238→                {
239→                    // for those outputs in boundary as there is no overlapping
240→                    // between ifm and kernel
241→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
242→                    out_tensor += in_tensor_ch;
243→                }
244→            }
245→        }
246→        in_tensor += input_len;
247→    }
248→#elif defined(ENA_DSP_ISA)
249→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
250→
251→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
252→    {
253→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
254→        {
255→            long ker_y_start = MAX(0, in_y);
256→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
257→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
258→            {
259→                long ker_x_start = MAX(0, in_x);
260→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
261→                uint32_t cur_ch;
262→
263→                if ((ker_y_end > ker_y_start) &&
264→                    (ker_x_end > ker_x_start))
265→                {
266→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
267→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
268→                    {
269→                        long_t sum_q31_0 = 0;
270→                        long_t sum_q31_1 = 0;
271→                        long_t sum_q31_2 = 0;
272→                        long_t sum_q31_3 = 0;
273→
274→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
275→                        {
276→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
277→                            {
278→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
279→                                suni_t in_q7x4 = simd_load_8(pIn, 0);
280→                                sum_q31_0 += in_q7x4.b8.b0;
281→                                sum_q31_1 += in_q7x4.b8.b1;
282→                                sum_q31_2 += in_q7x4.b8.b2;
283→                                sum_q31_3 += in_q7x4.b8.b3;
284→                            }
285→                        }
286→
287→                        suni_t out_q7x4;
288→                        out_q7x4.b8.b0 = sum_q31_0 / count;
289→                        out_q7x4.b8.b1 = sum_q31_1 / count;
290→                        out_q7x4.b8.b2 = sum_q31_2 / count;
291→                        out_q7x4.b8.b3 = sum_q31_3 / count;
292→                        simd_save_8((s8_t*)out_tensor, out_q7x4.l0);
293→                        out_tensor += SIMD_NUM_Q7;
294→                    }
295→
296→                    // rest channels
297→                    for (; cur_ch < in_tensor_ch; cur_ch++)
298→                    {
299→                        int sum = 0;
300→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
301→                        {
302→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
303→                            {
304→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
305→                                sum += *pIn;
306→                            }
307→                        }
308→
309→                        *out_tensor++ = sum / count;
310→                    }
311→                }
312→                else
313→                {
314→                    // for those outputs in boundary as there is no overlapping
315→                    // between ifm and kernel
316→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
317→                    out_tensor += in_tensor_ch;
318→                }
319→            }
320→        }
321→        in_tensor += input_len;
322→    }
323→#else
324→    int16_t   i_batch, i_ch_in, i_x, i_y;
325→    int16_t   k_x, k_y;
326→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
327→    const int32_t output_len = out_tensor_dim * out_tensor_dim * in_tensor_ch;
328→
329→    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
330→    {
331→        for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
332→        {
333→            for (i_y = 0; i_y < out_tensor_dim; i_y++)
334→            {
335→                for (i_x = 0; i_x < out_tensor_dim; i_x++)
336→                {
337→                    int       sum = 0;
338→                    int       count = 0;
339→                    for (k_y = i_y * stride - pad; k_y < i_y * stride - pad + ker_dim; k_y++)
340→                    {
341→                        for (k_x = i_x * stride - pad; k_x < i_x * stride - pad + ker_dim; k_x++)
342→                        {
343→                            if (k_y >= 0 && k_x >= 0 && k_y < in_tensor_dim && k_x < in_tensor_dim)
344→                            {
345→                                sum += in_tensor[i_ch_in + in_tensor_ch * (k_x + k_y * in_tensor_dim)];
346→                                count++;
347→                            }
348→                        }
349→                    }
350→
351→                    if (count == 0)
352→                    {
353→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = 0;
354→                    }
355→                    else
356→                    {
357→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = sum / count;
358→                    }
359→                }
360→            }
361→        }
362→        in_tensor += input_len;
363→        out_tensor += output_len;
364→    }
365→#endif
366→}
