long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
// Fixed-point reciprocal for division: multiplier = ceil(2^16 / count)
// vmulh.vx at e16 computes (val * multiplier) >> 16
// Using ceiling ensures we don't under-estimate for positive values.
// For negative values, arithmetic right shift rounds toward -inf
// instead of C's truncation toward zero, so we add (count-1) to
// negative accumulators before the multiply to correct this.
long multiplier = ((1L << 16) + count - 1) / count;
long in_tensor_ch2 = in_tensor_ch;
// Precompute row stride for pointer advancement
long row_stride = in_tensor_dim * in_tensor_ch;

