// Fixed-point reciprocal multiply instead of VDIV:
// For negative accumulators, add (count-1) before multiply
// to convert floor-rounding to truncation-toward-zero.
NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
NDS_VEC_VSRA_VI(NDS_VEC_V16, NDS_VEC_V0, 15);   // sign mask: 0 if >=0, -1 if <0
NDS_VEC_VAND_VX(NDS_VEC_V16, NDS_VEC_V16, count - 1); // 0 if >=0, (count-1) if <0
NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16); // bias negatives toward zero
NDS_VEC_VMULH_VX(NDS_VEC_V0, NDS_VEC_V0, multiplier);

